  rootHarness,
  orchestratorHarness,
  dashboardHarness,
];

/**
 * Get harness by ID
 */
export function getHarness(id: string): HarnessConfig | undefined {
  return harnesses.find((h) => h.id === id);
}

/**
 * Get pending features count for a harness
 */
export async function getPendingCount(harness: HarnessConfig): Promise<number> {
  try {
    const file = Bun.file(harness.featuresPath);
    const data = await file.json();
    return data.features?.filter((f: { passes?: boolean }) => !f.passes).length ?? 0;
  } catch {
    return 0;
  }
}

/**
 * Get next pending feature for a harness
 */
export async function getNextFeature(
  harness: HarnessConfig
): Promise<{ id: string; description: string } | null> {
  try {
    const file = Bun.file(harness.featuresPath);
    const data = await file.json();
    const next = data.features?.find((f: { passes?: boolean }) => !f.passes);
    return next ? { id: next.id, description: next.description } : null;
  } catch {
    return null;
  }
}

