/**
 * Parallel Harness Configuration
 *
 * Defines parallel execution groups (waves) for features.
 * Uses git worktrees to enable concurrent development without conflicts.
 *
 * Architecture:
 * - Main branch: main
 * - Feature branches: feat/<feature-id>
 * - Worktrees: .trees/<feature-id>/
 *
 * Each wave can run in parallel. Features within a wave that modify
 * the same files run sequentially within that wave.
 */

export interface ParallelFeature {
  id: string;
  description: string;
  priority: number;
  filesModified: string[];
  estimatedComplexity: 'low' | 'medium' | 'high';
}

export interface ParallelGroup {
  id: string;
  name: string;
  features: ParallelFeature[];
  sequential: boolean; // If true, features run sequentially in this group
  conflictRisk: 'low' | 'medium' | 'high';
}

export interface ParallelWave {
  wave: number;
  description: string;
  groups: ParallelGroup[];
  maxConcurrency: number;
  dependsOn: number | null; // Previous wave number that must complete
}

/**
 * Wave Configuration
 *
 * Based on file conflict analysis:
 * - InfiniteCanvas.tsx: HIGH conflict (event handlers)
 * - App.tsx: MEDIUM conflict (JSX layout)
 * - MicroLayer.tsx: LOW conflict (isolated rendering)
 */
export const waves: ParallelWave[] = [
  {
    wave: 1,
    description: 'Initial parallel execution - isolated features + grouped modifications',
    dependsOn: null,
    maxConcurrency: 3,
    groups: [
      {
        id: 'group-A',
        name: 'Dependency Lines (Isolated)',
        sequential: false,
        conflictRisk: 'low',
        features: [
          {
            id: 'F023',
            description: 'Dependency lines between tasks',
            priority: 4,
            filesModified: ['apps/canvas/src/canvas/layers/MicroLayer.tsx'],
            estimatedComplexity: 'medium',
          },
        ],
      },
      {
        id: 'group-B',
        name: 'Minimap System (App.tsx)',
        sequential: true, // F025 and F123 modify same area
        conflictRisk: 'medium',
        features: [
          {
            id: 'F123',
            description: 'Minimap navigation (bird\'s eye view)',
            priority: 3,
            filesModified: ['apps/canvas/src/App.tsx', 'apps/canvas/src/components/Minimap.tsx'],
            estimatedComplexity: 'high',
          },
          {
            id: 'F025',
            description: 'Time scrubber minimap',
            priority: 4,
            filesModified: ['apps/canvas/src/App.tsx', 'apps/canvas/src/components/Minimap.tsx'],
            estimatedComplexity: 'medium',
          },
        ],
      },
      {
        id: 'group-C',
        name: 'Scroll Modifiers (InfiniteCanvas)',
        sequential: true, // Both modify handleWheel
        conflictRisk: 'high',
        features: [
          {
            id: 'F016',
            description: 'Shift+Scroll for vertical pan',
            priority: 3,
            filesModified: ['apps/canvas/src/canvas/InfiniteCanvas.tsx'],
            estimatedComplexity: 'low',
          },
          {
            id: 'F017',
            description: 'Ctrl+Scroll for horizontal pan',
            priority: 3,
            filesModified: ['apps/canvas/src/canvas/InfiniteCanvas.tsx'],
            estimatedComplexity: 'low',
          },
        ],
      },
    ],
  },
  {
    wave: 2,
    description: 'Keyboard features + Task panel',
    dependsOn: 1,
    maxConcurrency: 2,
    groups: [
      {
        id: 'group-D',
        name: 'Keyboard Shortcuts (InfiniteCanvas)',
        sequential: true, // Share keyboard handler
        conflictRisk: 'high',
        features: [
          {
            id: 'F027',
            description: 'Keyboard shortcuts for zoom (+/-/0)',
            priority: 4,
            filesModified: ['apps/canvas/src/canvas/InfiniteCanvas.tsx'],
            estimatedComplexity: 'low',
          },
          {
            id: 'F028',
            description: 'Keyboard shortcuts for pan (arrows)',
            priority: 4,
            filesModified: ['apps/canvas/src/canvas/InfiniteCanvas.tsx'],
            estimatedComplexity: 'low',
          },
        ],
      },
      {
        id: 'group-E',
        name: 'Task Details Panel (App.tsx)',
        sequential: false,
        conflictRisk: 'medium',
        features: [
          {
            id: 'F026',
            description: 'Task details panel on selection',
            priority: 3,
            filesModified: ['apps/canvas/src/App.tsx', 'apps/canvas/src/components/TaskDetailsPanel.tsx'],
            estimatedComplexity: 'medium',
          },
        ],
      },
    ],
  },
  {
    wave: 3,
    description: 'Accessibility features (depends on keyboard nav)',
    dependsOn: 2,
    maxConcurrency: 2,
    groups: [
      {
        id: 'group-F',
        name: 'Keyboard Task Navigation (InfiniteCanvas)',
        sequential: false,
        conflictRisk: 'high',
        features: [
          {
            id: 'F021',
            description: 'Keyboard navigation for tasks (Tab/Arrow/Enter)',
            priority: 3,
            filesModified: [
              'apps/canvas/src/canvas/InfiniteCanvas.tsx',
              'apps/canvas/src/canvas/layers/MesoLayer.tsx',
              'apps/canvas/src/canvas/layers/MicroLayer.tsx',
            ],
            estimatedComplexity: 'high',
          },
        ],
      },
    ],
  },
  {
    wave: 4,
    description: 'Final accessibility (depends on F021)',
    dependsOn: 3,
    maxConcurrency: 1,
    groups: [
      {
        id: 'group-G',
        name: 'ARIA Labels (Accessibility)',
        sequential: false,
        conflictRisk: 'low',
        features: [
          {
            id: 'F022',
            description: 'ARIA labels for screen readers',
            priority: 3,
            filesModified: [
              'apps/canvas/src/canvas/InfiniteCanvas.tsx',
              'apps/canvas/src/canvas/layers/MicroLayer.tsx',
            ],
            estimatedComplexity: 'medium',
          },
        ],
      },
    ],
  },
];

/**
 * Get all features across all waves
 */
export function getAllFeatures(): ParallelFeature[] {
  return waves.flatMap((w) => w.groups.flatMap((g) => g.features));
}

/**
 * Get features for a specific wave
 */
export function getWaveFeatures(waveNum: number): ParallelFeature[] {
  const wave = waves.find((w) => w.wave === waveNum);
  return wave ? wave.groups.flatMap((g) => g.features) : [];
}

/**
 * Get total feature count
 */
export function getTotalFeatureCount(): number {
  return getAllFeatures().length;
}

/**
 * Calculate estimated parallel speedup
 * Assumes each feature takes ~1 unit of time
 */
export function getEstimatedSpeedup(): { sequential: number; parallel: number; speedup: string } {
  const sequential = getTotalFeatureCount();
  let parallel = 0;

  for (const wave of waves) {
    // Find the longest group in this wave (determines wave duration)
    const longestGroup = Math.max(...wave.groups.map((g) => g.features.length));
    parallel += longestGroup;
  }

  return {
    sequential,
    parallel,
    speedup: `${(sequential / parallel).toFixed(1)}x`,
  };
}

/**
 * Branch naming convention
 */
export function getBranchName(featureId: string): string {
  return `feat/${featureId.toLowerCase()}`;
}

/**
 * Worktree path
 */
export function getWorktreePath(featureId: string): string {
  return `.trees/${featureId.toLowerCase()}`;
}

