/**
 * Get features for a specific wave
 */
export function getWaveFeatures(waveNum: number): ParallelFeature[] {
  const wave = waves.find((w) => w.wave === waveNum);
  return wave ? wave.groups.flatMap((g) => g.features) : [];
}

/**
 * Get total feature count
 */
export function getTotalFeatureCount(): number {
  return getAllFeatures().length;
}

/**
 * Calculate estimated parallel speedup
 * Assumes each feature takes ~1 unit of time
 */
export function getEstimatedSpeedup(): { sequential: number; parallel: number; speedup: string } {
  const sequential = getTotalFeatureCount();
  let parallel = 0;

  for (const wave of waves) {
    // Find the longest group in this wave (determines wave duration)
    const longestGroup = Math.max(...wave.groups.map((g) => g.features.length));
    parallel += longestGroup;
  }

  return {
    sequential,
    parallel,
    speedup: `${(sequential / parallel).toFixed(1)}x`,
  };
}

/**
 * Branch naming convention
 */
export function getBranchName(featureId: string): string {
  return `feat/${featureId.toLowerCase()}`;
}

/**
 * Worktree path
 */
export function getWorktreePath(featureId: string): string {
  return `.trees/${featureId.toLowerCase()}`;
}

