#!/usr/bin/env bun
/**
 * MMS Parallel Harness Runner
 *
 * Executes features in parallel using git worktrees.
 * Each worktree runs an isolated Claude session.
 *
 * Usage:
 *   bun scripts/parallel-runner.ts           # Interactive mode
 *   bun scripts/parallel-runner.ts wave 1    # Execute wave 1
 *   bun scripts/parallel-runner.ts status    # Show current status
 *   bun scripts/parallel-runner.ts cleanup   # Remove all worktrees
 */

import { spawn } from 'child_process';
import { waves, getEstimatedSpeedup, getBranchName, getWorktreePath, type ParallelWave, type ParallelGroup } from './parallel-config';

// ─────────────────────────────────────────────────────────────────────────────
// COLORS
// ─────────────────────────────────────────────────────────────────────────────

const c = {
  reset: '\x1b[0m',
  bold: '\x1b[1m',
  dim: '\x1b[2m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m',
};

function print(msg: string) {
  console.log(msg);
}

function printHeader(title: string) {
  print(`\n${c.bold}${c.blue}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${c.reset}`);
  print(`${c.bold}${c.blue}  ${title}${c.reset}`);
  print(`${c.bold}${c.blue}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${c.reset}\n`);
}

function printSuccess(msg: string) {
  print(`${c.green}✓ ${msg}${c.reset}`);
}

function printError(msg: string) {
  print(`${c.red}✗ ${msg}${c.reset}`);
}

function printInfo(msg: string) {
  print(`${c.blue}ℹ ${msg}${c.reset}`);
}

function printWarning(msg: string) {
  print(`${c.yellow}⚠ ${msg}${c.reset}`);
}

// ─────────────────────────────────────────────────────────────────────────────
// MACOS NOTIFICATIONS
// ─────────────────────────────────────────────────────────────────────────────

async function notify(title: string, message: string, sound: string = 'Ping') {
  try {
    const proc = Bun.spawn([
      'osascript',
      '-e',
      `display notification "${message}" with title "${title}" sound name "${sound}"`,
    ]);
    await proc.exited;
  } catch {
    // Ignore notification errors
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// GIT WORKTREE MANAGEMENT
// ─────────────────────────────────────────────────────────────────────────────

async function runCommand(cmd: string, args: string[], cwd?: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  const proc = Bun.spawn([cmd, ...args], {
    cwd: cwd ?? process.cwd(),
    stdout: 'pipe',
    stderr: 'pipe',
  });

  const stdout = await new Response(proc.stdout).text();
  const stderr = await new Response(proc.stderr).text();
  const exitCode = await proc.exited;

  return { stdout, stderr, exitCode };
}

async function createWorktree(featureId: string): Promise<boolean> {
  const branchName = getBranchName(featureId);
  const worktreePath = getWorktreePath(featureId);

  printInfo(`Creating worktree for ${featureId}...`);

  // Check if worktree already exists
  const { stdout: worktreeList } = await runCommand('git', ['worktree', 'list']);
  if (worktreeList.includes(worktreePath)) {
    printWarning(`Worktree ${worktreePath} already exists`);
    return true;
  }

  // Check if branch exists
  const { exitCode: branchExists } = await runCommand('git', ['rev-parse', '--verify', branchName]);

  if (branchExists === 0) {
    // Branch exists, create worktree with existing branch
    const { exitCode, stderr } = await runCommand('git', ['worktree', 'add', worktreePath, branchName]);
    if (exitCode !== 0) {
      printError(`Failed to create worktree: ${stderr}`);
      return false;
    }
  } else {
    // Create new branch from main
    const { exitCode, stderr } = await runCommand('git', ['worktree', 'add', '-b', branchName, worktreePath, 'main']);
    if (exitCode !== 0) {
      printError(`Failed to create worktree with new branch: ${stderr}`);
      return false;
    }
  }

  printSuccess(`Created worktree ${worktreePath} on branch ${branchName}`);
  return true;
}

async function removeWorktree(featureId: string): Promise<boolean> {
  const worktreePath = getWorktreePath(featureId);

  printInfo(`Removing worktree ${worktreePath}...`);

  const { exitCode, stderr } = await runCommand('git', ['worktree', 'remove', worktreePath, '--force']);
  if (exitCode !== 0 && !stderr.includes('is not a working tree')) {
    printError(`Failed to remove worktree: ${stderr}`);
    return false;
  }

  printSuccess(`Removed worktree ${worktreePath}`);
  return true;
}

async function listWorktrees(): Promise<string[]> {
  const { stdout } = await runCommand('git', ['worktree', 'list']);
  return stdout.split('\n').filter(Boolean);
}

// ─────────────────────────────────────────────────────────────────────────────
// FEATURE STATUS
// ─────────────────────────────────────────────────────────────────────────────

async function getFeatureStatus(featureId: string): Promise<'pending' | 'complete' | 'in-progress'> {
  try {
    const file = Bun.file('features.json');
    const data = await file.json();
    const feature = data.features?.find((f: { id: string }) => f.id === featureId);

    if (!feature) return 'pending';
    if (feature.passes === true) return 'complete';

    // Check if worktree exists (in-progress)
    const worktreePath = getWorktreePath(featureId);
    const { stdout } = await runCommand('git', ['worktree', 'list']);
    if (stdout.includes(worktreePath)) return 'in-progress';

    return 'pending';
  } catch {
    return 'pending';
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// CLAUDE SESSION MANAGEMENT
// ─────────────────────────────────────────────────────────────────────────────

interface ClaudeSession {
  featureId: string;
  process: ReturnType<typeof spawn>;
  startTime: Date;
}

const activeSessions: Map<string, ClaudeSession> = new Map();

function getIsolationPrompt(featureId: string, groupName: string): string {
  return `You are working on feature ${featureId} in the MMS project.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🎯 FEATURE: ${featureId}
📦 GROUP: ${groupName}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

📋 HARNESS PROTOCOL (PARALLEL MODE)
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

1. READ claude-progress.txt → current state
2. READ features.json → find ${featureId} details
3. IMPLEMENT ONLY ${featureId} (do not touch other features)
4. TEST visually with Playwright MCP
5. UPDATE features.json → set ${featureId} passes: true
6. UPDATE claude-progress.txt → add session notes
7. COMMIT changes with message: feat(canvas): ${featureId} - <description>

⚠️  IMPORTANT: This is a PARALLEL execution. Other features are being
worked on simultaneously in other worktrees. DO NOT modify files
outside the scope of ${featureId}.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
When done with ${featureId}, type /exit to complete this session.
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`;
}

async function startClaudeSession(featureId: string, groupName: string, worktreePath: string): Promise<void> {
  const isolationPrompt = getIsolationPrompt(featureId, groupName);
  const absolutePath = `${process.cwd()}/${worktreePath}`;

  printInfo(`Starting Claude session for ${featureId} in ${worktreePath}...`);

  // Create a new terminal window for each Claude session (macOS)
  const script = `
    tell application "Terminal"
      do script "cd '${absolutePath}' && claude --append-system-prompt '${isolationPrompt.replace(/'/g, "'\\''")}'"
      activate
    end tell
  `;

  const proc = spawn('osascript', ['-e', script], {
    detached: true,
    stdio: 'ignore',
  });

  proc.unref();

  activeSessions.set(featureId, {
    featureId,
    process: proc,
    startTime: new Date(),
  });

  printSuccess(`Claude session started for ${featureId}`);
  await notify('🚀 Parallel Harness', `Started ${featureId}`, 'Submarine');
}

// ─────────────────────────────────────────────────────────────────────────────
// WAVE EXECUTION
// ─────────────────────────────────────────────────────────────────────────────

async function executeWave(waveNum: number): Promise<void> {
  const wave = waves.find((w) => w.wave === waveNum);
  if (!wave) {
    printError(`Wave ${waveNum} not found`);
    return;
  }

  printHeader(`🌊 WAVE ${wave.wave}: ${wave.description}`);

  // Check dependencies
  if (wave.dependsOn !== null) {
    const prevWave = waves.find((w) => w.wave === wave.dependsOn);
    if (prevWave) {
      const prevFeatures = prevWave.groups.flatMap((g) => g.features);
      for (const f of prevFeatures) {
        const status = await getFeatureStatus(f.id);
        if (status !== 'complete') {
          printError(`Wave ${waveNum} blocked: ${f.id} from Wave ${wave.dependsOn} is not complete`);
          printInfo('Complete previous wave first, then run this wave.');
          return;
        }
      }
    }
  }

  print(`${c.dim}Max concurrency: ${wave.maxConcurrency}${c.reset}\n`);

  // Process groups
  const groupPromises: Promise<void>[] = [];

  for (const group of wave.groups) {
    groupPromises.push(executeGroup(group, wave.maxConcurrency));
  }

  // Wait for all groups in this wave
  await Promise.all(groupPromises);

  printSuccess(`Wave ${waveNum} initiated. Monitor each terminal for progress.`);
  await notify('🌊 Wave Started', `Wave ${waveNum}: ${wave.groups.length} groups running`, 'Glass');
}

async function executeGroup(group: ParallelGroup, maxConcurrency: number): Promise<void> {
  print(`\n${c.cyan}📦 Group: ${group.name}${c.reset}`);
  print(`${c.dim}   Risk: ${group.conflictRisk} | Sequential: ${group.sequential}${c.reset}`);

  if (group.sequential) {
    // Sequential execution within group
    printInfo('Features in this group run sequentially (same file conflicts)');

    for (const feature of group.features) {
      const status = await getFeatureStatus(feature.id);

      if (status === 'complete') {
        printSuccess(`${feature.id}: Already complete`);
        continue;
      }

      if (status === 'in-progress') {
        printWarning(`${feature.id}: Already in progress`);
        continue;
      }

      // Create worktree and start session
      const created = await createWorktree(feature.id);
      if (created) {
        const worktreePath = getWorktreePath(feature.id);
        await startClaudeSession(feature.id, group.name, worktreePath);
      }

      // For sequential groups, we only start one at a time
      // User must complete and merge before next starts
      printInfo(`Complete ${feature.id}, merge to main, then run next feature in group.`);
      break;
    }
  } else {
    // Parallel execution within group
    for (const feature of group.features) {
      const status = await getFeatureStatus(feature.id);

      if (status === 'complete') {
        printSuccess(`${feature.id}: Already complete`);
        continue;
      }

      if (status === 'in-progress') {
        printWarning(`${feature.id}: Already in progress`);
        continue;
      }

      // Create worktree and start session
      const created = await createWorktree(feature.id);
      if (created) {
        const worktreePath = getWorktreePath(feature.id);
        await startClaudeSession(feature.id, group.name, worktreePath);
      }
    }
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// STATUS DISPLAY
// ─────────────────────────────────────────────────────────────────────────────

async function showStatus(): Promise<void> {
  printHeader('📊 PARALLEL HARNESS STATUS');

  const speedup = getEstimatedSpeedup();
  print(`${c.cyan}Estimated speedup: ${speedup.speedup} (${speedup.sequential} sequential → ${speedup.parallel} parallel)${c.reset}\n`);

  // Show worktrees
  const worktrees = await listWorktrees();
  print(`${c.bold}Active Worktrees:${c.reset}`);
  for (const wt of worktrees) {
    print(`  ${c.dim}${wt}${c.reset}`);
  }

  print('');

  // Show wave status
  for (const wave of waves) {
    const waveStatus = wave.dependsOn
      ? `${c.yellow}(blocked by Wave ${wave.dependsOn})${c.reset}`
      : `${c.green}(ready)${c.reset}`;

    print(`${c.bold}Wave ${wave.wave}: ${wave.description} ${waveStatus}${c.reset}`);

    for (const group of wave.groups) {
      print(`  ${c.cyan}├─ ${group.name}${c.reset} (${group.conflictRisk} risk)`);

      for (const feature of group.features) {
        const status = await getFeatureStatus(feature.id);
        const statusIcon = status === 'complete' ? `${c.green}✓${c.reset}` : status === 'in-progress' ? `${c.yellow}⟳${c.reset}` : `${c.dim}○${c.reset}`;
        print(`  │  ${statusIcon} ${feature.id}: ${feature.description}`);
      }
    }
    print('');
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// CLEANUP
// ─────────────────────────────────────────────────────────────────────────────

async function cleanup(): Promise<void> {
  printHeader('🧹 CLEANING UP WORKTREES');

  const { stdout } = await runCommand('git', ['worktree', 'list']);
  const lines = stdout.split('\n').filter(Boolean);

  // Skip the main worktree
  for (const line of lines.slice(1)) {
    const path = line.split(/\s+/)[0];
    if (path.includes('.trees/')) {
      const featureId = path.split('/').pop()?.toUpperCase();
      if (featureId) {
        await removeWorktree(featureId);
      }
    }
  }

  // Remove .trees directory if empty
  await runCommand('rm', ['-rf', '.trees']);

  printSuccess('Cleanup complete');
}

// ─────────────────────────────────────────────────────────────────────────────
// MERGE HELPER
// ─────────────────────────────────────────────────────────────────────────────

async function mergeFeature(featureId: string): Promise<void> {
  const branchName = getBranchName(featureId);
  const worktreePath = getWorktreePath(featureId);

  printHeader(`🔀 MERGING ${featureId}`);

  // Check if feature is complete
  const status = await getFeatureStatus(featureId);
  if (status !== 'complete') {
    printWarning(`Feature ${featureId} is not marked as complete in features.json`);
    printInfo('Mark passes: true before merging.');
    return;
  }

  // Switch to main and merge
  printInfo('Switching to main branch...');
  await runCommand('git', ['checkout', 'main']);

  printInfo(`Merging ${branchName}...`);
  const { exitCode, stderr } = await runCommand('git', ['merge', branchName, '--no-ff', '-m', `Merge ${branchName}: ${featureId}`]);

  if (exitCode !== 0) {
    printError(`Merge failed: ${stderr}`);
    printInfo('Resolve conflicts manually, then run: git merge --continue');
    return;
  }

  printSuccess(`Merged ${branchName} to main`);

  // Remove worktree
  await removeWorktree(featureId);

  // Delete branch
  await runCommand('git', ['branch', '-d', branchName]);

  printSuccess(`Cleanup complete for ${featureId}`);
  await notify('✅ Feature Merged', `${featureId} merged to main`, 'Glass');
}

// ─────────────────────────────────────────────────────────────────────────────
// INTERACTIVE MENU
// ─────────────────────────────────────────────────────────────────────────────

async function showMenu(): Promise<void> {
  printHeader('🔧 MMS PARALLEL HARNESS RUNNER');

  const speedup = getEstimatedSpeedup();
  print(`${c.cyan}Estimated speedup: ${speedup.speedup}${c.reset}\n`);

  print('Commands:');
  print(`  ${c.green}1${c.reset}. Execute Wave 1 (Initial parallel)`);
  print(`  ${c.green}2${c.reset}. Execute Wave 2 (Keyboard + Panel)`);
  print(`  ${c.green}3${c.reset}. Execute Wave 3 (Accessibility)`);
  print(`  ${c.green}4${c.reset}. Execute Wave 4 (ARIA labels)`);
  print(`  ${c.yellow}s${c.reset}. Show status`);
  print(`  ${c.yellow}c${c.reset}. Cleanup worktrees`);
  print(`  ${c.yellow}m${c.reset}. Merge a feature`);
  print(`  ${c.dim}q${c.reset}. Quit`);
  print('');

  process.stdout.write(`${c.bold}> ${c.reset}`);

  const reader = Bun.stdin.stream().getReader();
  const { value } = await reader.read();
  reader.releaseLock();

  if (!value) return;

  const input = new TextDecoder().decode(value).trim().toLowerCase();

  switch (input) {
    case '1':
      await executeWave(1);
      break;
    case '2':
      await executeWave(2);
      break;
    case '3':
      await executeWave(3);
      break;
    case '4':
      await executeWave(4);
      break;
    case 's':
      await showStatus();
      break;
    case 'c':
      await cleanup();
      break;
    case 'm':
      print('Enter feature ID to merge (e.g., F023): ');
      const reader2 = Bun.stdin.stream().getReader();
      const { value: val2 } = await reader2.read();
      reader2.releaseLock();
      if (val2) {
        const featureId = new TextDecoder().decode(val2).trim().toUpperCase();
        await mergeFeature(featureId);
      }
      break;
    case 'q':
      print('\nGoodbye!');
      process.exit(0);
    default:
      printError('Invalid option');
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// MAIN
// ─────────────────────────────────────────────────────────────────────────────

async function main() {
  const args = process.argv.slice(2);

  if (args.length === 0) {
    // Interactive mode
    await showMenu();
  } else {
    const command = args[0];

    switch (command) {
      case 'wave':
        const waveNum = parseInt(args[1], 10);
        if (isNaN(waveNum)) {
          printError('Invalid wave number');
          process.exit(1);
        }
        await executeWave(waveNum);
        break;

      case 'status':
        await showStatus();
        break;

      case 'cleanup':
        await cleanup();
        break;

      case 'merge':
        const featureId = args[1]?.toUpperCase();
        if (!featureId) {
          printError('Feature ID required');
          process.exit(1);
        }
        await mergeFeature(featureId);
        break;

      default:
        print(`
Usage:
  bun scripts/parallel-runner.ts              # Interactive mode
  bun scripts/parallel-runner.ts wave <num>   # Execute wave
  bun scripts/parallel-runner.ts status       # Show status
  bun scripts/parallel-runner.ts cleanup      # Remove worktrees
  bun scripts/parallel-runner.ts merge <id>   # Merge feature
`);
    }
  }
}

main().catch((err) => {
  printError(`Error: ${err.message}`);
  process.exit(1);
});

